<?php class Model_Mapper_Encuesta{	private static $_instance;		public static function getInstance()	{		if(null == self::$_instance)		{			self::$_instance = new self;		}		return self::$_instance;	}	private function __construct(){}	public function getEncuestas()	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchAll($db->select()->from('tbl_encuesta'));	}		public function getEncuestaActiva()	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()	->from('tbl_encuesta')											->where('estatus_encuesta = 1'));	}	}